#include <stdio.h>
#include <stdlib.h>

void** allocate_2d_matrix(size_t rows, size_t cols) {
    void **data = malloc(rows * sizeof(void*));
    if (NULL == data) {
        perror("malloc");
        return NULL;
    }
    
    for (size_t i = 0; i < rows; ++i){
        data[i] = malloc(cols * sizeof(double)); // Assuming the matrix elements are of type double
        if (NULL == data[i]) {
            perror("malloc");
            for (size_t j = 0; j < i; ++j) {
                free(data[j]);
            }
            free(data);
            return NULL;
        }
    }
    
    return data;
}